import {
  _decorator,
  CCBoolean,
  Component,
  Enum,
  Node,
  tween,
  UIOpacity,
  UITransform,
  Vec3,
  Widget,
} from "cc";
import { BaseUI } from "./BaseUI";
import PLK from "../PLK";
import { AudioManager } from "../manager/AudioManager";
import { AniType } from "../types/global.d";
import { MessageFlag } from "../manager/MessageFlag";
import { UIType } from "../eui/UIkeys";
import logger from "../utils/logger";
const { ccclass, property } = _decorator;

@ccclass("BasePanel")
export class BasePanel extends BaseUI {
  private closeBtn: Node = null;
  protected closeWithMask: boolean = false;
  protected aniType: AniType = AniType.none;
  protected uiType: UIType = UIType.panel;

  onLoad() {
    // 确保Widget组件先生效，然后执行动画
    this.ensureWidgetUpdatedThenShowAni();

    if (this.closeWithMask) {
      this.node.parent.on(Node.EventType.TOUCH_END, this.onMaskClick, this);
    }
    this.closeBtn =
      this.node.getChildByName("closeBtn") ||
      this.findChildRecursively(this.node, "closeBtn");
    if (this.closeBtn) {
      this.closeBtn.on(Node.EventType.TOUCH_END, this.close, this);
    }
  }

  /**
   * 处理遮罩点击事件
   * 只有当点击目标不是面板本身或其子节点时才关闭面板
   */
  private onMaskClick(event: any) {
    const target = event.target;

    // 检查点击目标是否是当前面板或其子节点
    if (this.isNodeChildOf(target, this.node)) {
      // 如果点击的是面板内部的元素，不关闭面板
      return;
    }

    PLK.event.emit(MessageFlag.MASK_CHANGE, { isShow: false, node: null });

    // 如果点击的是背景区域，关闭面板
    this.close(false);
  }

  /**
   * 检查节点是否是指定父节点的子节点
   */
  private isNodeChildOf(child: Node, parent: Node): boolean {
    if (!child || !parent) {
      return false;
    }

    if (child === parent) {
      return true;
    }

    let currentParent = child.parent;
    while (currentParent) {
      if (currentParent === parent) {
        return true;
      }
      currentParent = currentParent.parent;
    }

    return false;
  }

  /**
   * 确保Widget组件更新后再执行动画
   */
  private ensureWidgetUpdatedThenShowAni() {
    const widget = this.node.getComponent(Widget);
    if (widget) {
      // 简单延迟，让Widget组件自然完成布局更新
      // 不手动调用updateAlignment，避免重复更新导致闪现
      this.scheduleOnce(() => {
        this.showAni();
      }, 0.01); // 稍微增加延迟时间，确保Widget完成更新
    } else {
      // 没有Widget组件，直接执行动画
      this.showAni();
    }
  }

  /**
   * 递归查找子节点
   * @param parent 父节点
   * @param name 要查找的节点名称
   * @returns 找到的节点或null
   */
  private findChildRecursively(parent: Node, name: string): Node | null {
    // 先检查直接子节点
    for (let i = 0; i < parent.children.length; i++) {
      const child = parent.children[i];
      if (child.name === name) {
        return child;
      }
    }

    // 递归检查子节点的子节点
    for (let i = 0; i < parent.children.length; i++) {
      const child = parent.children[i];
      const found = this.findChildRecursively(child, name);
      if (found) {
        return found;
      }
    }

    return null;
  }

  close(
    playClick: boolean = true,
    callback: () => void = null,
    closeMask: boolean = true,
  ) {
    if (playClick) {
      AudioManager.getInstance().playEffectByName("click2");
    }

    if (this.closeWithMask || closeMask) {
      PLK.event.emit(MessageFlag.MASK_CHANGE, { isShow: false, node: null });
    }

    if (this.closeWithMask) {
      this.node?.parent?.off(Node.EventType.TOUCH_END, this.onMaskClick, this);
    }

    switch (this.aniType) {
      case AniType.center:
        this.closeWithCenter(callback);
        break;
      case AniType.left:
        this.closeWithLeft(callback);
        break;
      case AniType.right:
        this.closeWithRight(callback);
        break;
      case AniType.bottom:
        this.closeWithBottom(callback);
        break;
      case AniType.top:
        this.closeWithTop(callback);
        break;
      case AniType.opacity:
        this.closeWithOpacity(callback);
        break;
      default:
        this.closeNoAni(callback);
    }
  }

  removePanel() {
    if (this.uiType === UIType.panel) {
      PLK.ui.removePanel(this.node);
    } else if (this.uiType === UIType.popup) {
      PLK.ui.removePopup(this.node);
    }
  }

  showAni() {
    switch (this.aniType) {
      case AniType.center:
        this.openWithCenter();
        break;
      case AniType.left:
        this.openWithLeft();
        break;
      case AniType.right:
        this.openWithRight();
        break;
      case AniType.top:
        this.openWithTop();
        break;
      case AniType.bottom:
        this.openWithBottom();
        break;
      case AniType.opacity:
        this.openWithOpacity();
        break;
      default:
        this.openNoAni();
    }
  }

  openWithRight() {
    const nodeWidth = this.node.getComponent(UITransform).width;
    const parentWidth = PLK.ui.sceneWidth;

    // 获取Widget生效后的正确Y位置
    const widgetAdjustedY = this.node.position.y;

    // 右侧开启：从右侧外边缘滑入到内边缘
    const startX = (parentWidth - nodeWidth) / 2 + nodeWidth;
    const targetX = 0; //startX - nodeWidth  // 与计算规则一致

    // 先设置起始位置，避免在tween中设置active导致闪现
    this.node.setPosition(startX, widgetAdjustedY, 0);
    this.node.getComponent(UIOpacity) &&
      (this.node.getComponent(UIOpacity).opacity = 255);
    tween(this.node)
      .to(0.2, { position: new Vec3(targetX, widgetAdjustedY, 0) })
      .start();
  }

  closeWithRight(callback: () => void) {
    const nodeWidth = this.node.getComponent(UITransform).width;
    const parentWidth = PLK.ui.sceneWidth;

    // 右侧关闭：移动到右侧外边缘
    const targetX = (parentWidth - nodeWidth) / 2 + nodeWidth;

    tween(this.node)
      .to(0.2, { position: new Vec3(targetX, this.node.position.y, 0) })
      .call(() => {
        this.removePanel();
        callback && callback();
      })
      .start();
  }

  openWithBottom() {
    const nodeHeight = this.node.getComponent(UITransform).height;
    const parentHeight = PLK.ui.sceneHeight;

    // 获取Widget生效后的正确X位置
    const widgetAdjustedX = this.node.position.x;

    // 底部开启：从底部外边缘滑入到内边缘
    const startY = -((parentHeight - nodeHeight) / 2 + nodeHeight);
    const targetY = startY + nodeHeight; // 与计算规则一致

    // 先设置起始位置，避免在tween中设置active导致闪现
    this.node.setPosition(widgetAdjustedX, startY, 0);
    this.node.getComponent(UIOpacity) &&
      (this.node.getComponent(UIOpacity).opacity = 255);
    tween(this.node)
      .to(0.2, { position: new Vec3(widgetAdjustedX, targetY, 0) })
      .start();
  }

  openWithLeft() {
    const nodeWidth = this.node.getComponent(UITransform).width;
    const parentWidth = PLK.ui.sceneWidth;

    // 获取Widget生效后的正确Y位置
    const widgetAdjustedY = this.node.position.y;

    // 左侧开启：从左侧外边缘滑入到内边缘
    const startX = -((parentWidth - nodeWidth) / 2 + nodeWidth);
    const targetX = 0; //startX + nodeWidth  // 与Menu.ts中的计算一致

    // 先设置起始位置，避免在tween中设置active导致闪现
    this.node.setPosition(startX, widgetAdjustedY, 0);
    this.node.getComponent(UIOpacity) &&
      (this.node.getComponent(UIOpacity).opacity = 255);
    tween(this.node)
      .to(0.2, { position: new Vec3(targetX, widgetAdjustedY, 0) })
      .start();
  }

  openWithTop() {
    const nodeHeight = this.node.getComponent(UITransform).height;
    const parentHeight = PLK.ui.sceneHeight;

    // 获取Widget生效后的正确X位置
    const widgetAdjustedX = this.node.position.x;

    // 顶部开启：从顶部外边缘滑入到内边缘
    const startY = (parentHeight - nodeHeight) / 2 + nodeHeight;
    const targetY = startY - nodeHeight; // 与计算规则一致

    // 先设置起始位置，避免在tween中设置active导致闪现
    this.node.setPosition(widgetAdjustedX, startY, 0);
    this.node.getComponent(UIOpacity) &&
      (this.node.getComponent(UIOpacity).opacity = 255);
    tween(this.node)
      .to(0.2, { position: new Vec3(widgetAdjustedX, targetY, 0) })
      .start();
  }

  openWithCenter() {
    // 中心开启：从小到大出现
    // 设置初始缩放为0
    this.node.setScale(0, 0, 1);
    this.node.getComponent(UIOpacity) &&
      (this.node.getComponent(UIOpacity).opacity = 255);

    // 缩放到正常大小
    tween(this.node)
      .to(0.2, { scale: new Vec3(1, 1, 1) })
      .start();
  }

  closeWithBottom(callback: () => void) {
    const nodeHeight = this.node.getComponent(UITransform).height;
    const parentHeight = PLK.ui.sceneHeight;

    // 底部关闭：移动到底部外边缘
    const targetY = -((parentHeight - nodeHeight) / 2 + nodeHeight);

    tween(this.node)
      .to(0.2, { position: new Vec3(this.node.position.x, targetY, 0) })
      .call(() => {
        this.removePanel();
        callback && callback();
      })
      .start();
  }

  closeWithLeft(callback: () => void) {
    const nodeWidth = this.node.getComponent(UITransform).width;
    const parentWidth = PLK.ui.sceneWidth;

    // 左侧关闭：移动到左侧外边缘
    const targetX = -((parentWidth - nodeWidth) / 2 + nodeWidth);

    tween(this.node)
      .to(0.2, { position: new Vec3(targetX, this.node.position.y, 0) })
      .call(() => {
        this.removePanel();
        callback && callback();
      })
      .start();
  }

  closeWithTop(callback: () => void) {
    const nodeHeight = this.node.getComponent(UITransform).height;
    const parentHeight = PLK.ui.sceneHeight;

    // 顶部关闭：移动到顶部外边缘
    const targetY = (parentHeight - nodeHeight) / 2 + nodeHeight;

    tween(this.node)
      .to(0.2, { position: new Vec3(this.node.position.x, targetY, 0) })
      .call(() => {
        this.removePanel();
        callback && callback();
      })
      .start();
  }

  closeWithCenter(callback: () => void) {
    // 中心关闭：从大到小消失
    tween(this.node)
      .to(0.2, { scale: new Vec3(0, 0, 1) })
      .call(() => {
        this.removePanel();
        callback && callback();
      })
      .start();
  }

  openNoAni() {
    tween(this.node.getComponent(UIOpacity))
      .set({ opacity: 0 })
      .to(0.3, { opacity: 255 })
      .start();
  }

  closeNoAni(callback: () => void) {
    tween(this.node.getComponent(UIOpacity))
      .to(0.2, { opacity: 0 })
      .call(() => {
        this.removePanel();
        callback && callback();
      })
      .start();
  }

  openWithOpacity() {
    // 透明度淡入：从透明到不透明
    let uiOpacity = this.node.getComponent(UIOpacity);
    if (!uiOpacity) {
      // 如果没有UIOpacity组件，添加一个
      uiOpacity = this.node.addComponent(UIOpacity);
    }
    // 设置初始透明度为0
    uiOpacity.opacity = 0;
    // 淡入到不透明
    tween(uiOpacity).to(0.3, { opacity: 255 }).start();
  }

  closeWithOpacity(callback: () => void) {
    // 透明度淡出：从不透明到透明
    const uiOpacity = this.node.getComponent(UIOpacity);
    if (uiOpacity) {
      tween(uiOpacity)
        .to(0.3, { opacity: 0 })
        .call(() => {
          this.removePanel();
          callback && callback();
        })
        .start();
    } else {
      // 如果没有UIOpacity组件，直接关闭
      this.removePanel();
      callback && callback();
    }
  }
}
